import { NavLink } from "react-router-dom";
import React, { useState, useEffect, useRef } from "react";
import "./Header.css";

export default function Header() {
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const searchRef = useRef(null);

  // კლიკის დეტექცია გარეთ
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setSearchOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const handleSearchToggle = () => {
    setSearchOpen((prev) => !prev);
  };

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    if (searchQuery.trim() === "") return;
    alert(`ძებნა: ${searchQuery}`); 
    setSearchQuery("");
    setSearchOpen(false);
  };

  return (
    <header className="header">
      {/* Logo */}
      <div className="logo">
        <a href="#hero">
          <img src="/logo.png" alt="MBTI Logo" />
        </a>
      </div>

      {/* Nav */}
      <nav className="nav">
        <ul>
          <li><a href="#hero" className="active">მთავარი</a></li>
          <li>
  <NavLink
    to="/mbti-dimensions"
    className={({ isActive }) => (isActive ? "active" : "")}
  >
    MBTI განზომილებები
  </NavLink>
</li>

          <li><a href="#article">სტატიები</a></li>
          <li><a href="#start-test">დაიწყე ტესტი</a></li>
          <li><a href="#register">Sign in</a></li>

          {/* Search toggle */}
          <li className="search-wrapper" ref={searchRef}>
            <button
              className="search-toggle"
              onClick={handleSearchToggle}
              aria-label="ძებნა"
            >
              <img src="/search.png" alt="ძებნა" className="search-icon" />
            </button>
            {searchOpen && (
              <form className="search-form" onSubmit={handleSearchSubmit}>
                <input
                  type="text"
                  placeholder="ძებნა საიტზე..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  autoFocus
                />
                <button type="submit">ძიება</button>
              </form>
            )}
          </li>
        </ul>
      </nav>
    </header>
  );
}
